```python
import pygame
import random
from enum import Enum
from task0 import GRID_WIDTH, GRID_HEIGHT, CellState, Cell, Grid, ROT_90, ROT_180, ROT_270, rotate_point, generate_rotations, BASE_SHAPES, TETROMINO_COLORS, Tetromino

# Pygame Constants
SCREEN_WIDTH = 600
SCREEN_HEIGHT = 800
GRID_LINE_COLOR = (50, 50, 50)
EMPTY_COLOR = (30, 30, 30)
BLOCK_SIZE = 30
SPAWN_X = GRID_WIDTH // 2 - 2
SPAWN_Y = 0
PREVIEW_SIZE = 4
PREVIEW_POS = (450, 100)

class GameState(Enum):
    ACTIVE = 0
    PAUSED = 1
    GAME_OVER = 2

class TetrisJeweled:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris Jeweled")
        self.clock = pygame.time.Clock()
        self.grid = Grid()
        self.current_tetromino = self.new_tetromino()
        self.next_tetromino = self.new_tetromino()
        self.tetromino_x = SPAWN_X
        self.tetromino_y = SPAWN_Y
        self.game_state = GameState.ACTIVE
        self.score = 0
        self.drop_speed = 500 # milliseconds
        self.last_drop_time = pygame.time.get_ticks()
        self.animation_frames = 6
        self.animation_timer = 0

    def new_tetromino(self):
        return Tetromino(random.choice(list(BASE_SHAPES.keys())))

    def run(self):
        running = True
        while running:
            delta_time = self.clock.tick(60) / 1000.0
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(-1, 0)
                    if event.key == pygame.K_RIGHT and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(1, 0)
                    if event.key == pygame.K_DOWN and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(0, 1)
                    if event.key == pygame.K_UP and self.game_state == GameState.ACTIVE:
                        self.rotate_tetromino()
                    if event.key == pygame.K_SPACE and self.game_state == GameState.ACTIVE:
                        self.drop_tetromino()
                    if event.key == pygame.K_p:
                        if self.game_state == GameState.ACTIVE:
                            self.game_state = GameState.PAUSED
                        elif self.game_state == GameState.PAUSED:
                            self.game_state = GameState.ACTIVE

            if self.game_state == GameState.ACTIVE:
                self.update(delta_time)
            self.render()
            pygame.display.flip()

        pygame.quit()

    def update(self, delta_time):
        time_now = pygame.time.get_ticks()
        if time_now - self.last_drop_time > self.drop_speed:
            self.move_tetromino(0, 1)
            self.last_drop_time = time_now

        if self.animation_timer > 0:
            self.animation_timer -= 1

    def move_tetromino(self, dx, dy):
        new_x = self.tetromino_x + dx
        new_y = self.tetromino_y + dy
        if self.is_valid_position(new_x, new_y, self.current_tetromino):
            self.tetromino_x = new_x
            self.tetromino_y = new_y
        elif dy != 0:  # Attempting to move down and collision occurred
            self.lock_tetromino()

    def rotate_tetromino(self):
        original_rotation_index = self.current_tetromino.rotation_index
        self.current_tetromino.rotate()
        if not self.is_valid_position(self.tetromino_x, self.tetromino_y, self.current_tetromino):
            # Revert rotation if the new position is invalid
            self.current_tetromino.rotation_index = original_rotation_index
            self.current_tetromino.blocks = list(self.current_tetromino.rotations[original_rotation_index])

    def drop_tetromino(self):
        while self.is_valid_position(self.tetromino_x, self.tetromino_y + 1, self.current_tetromino):
            self.tetromino_y += 1
        self.lock_tetromino()

    def is_valid_position(self, x, y, tetromino):
        for block_x, block_y in tetromino.get_blocks(x, y):
            if not self.grid.is_inside(block_x, block_y) or self.grid.get_cell(block_x, block_y).state == CellState.FILLED:
                return False
        return True

    def lock_tetromino(self):
        for block_x, block_y in self.current_tetromino.get_blocks(self.tetromino_x, self.tetromino_y):
            self.grid.set_cell(block_x, block_y, CellState.FILLED, self.current_tetromino.color)
        self.clear_lines()
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.new_tetromino()
        self.tetromino_x = SPAWN_X
        self.tetromino_y = SPAWN_Y
        if not self.is_valid_position(self.tetromino_x, self.tetromino_y, self.current_tetromino):
            self.game_state = GameState.GAME_OVER

    def clear_lines(self):
          lines_cleared = 0
          y = self.grid.height - 1
          while y >= 0:
              if all(self.grid.get_cell(x, y).state == CellState.FILLED for x in range(self.grid.width)):
                  # Clear the line
                  for x in range(self.grid.width):
                      self.grid.set_cell(x, y, CellState.EMPTY, None)
                  # Move all lines above down by one
                  for yy in range(y - 1, -1, -1):
                      for x in range(self.grid.width):
                          cell = self.grid.get_cell(x, yy)
                          self.grid.set_cell(x, yy + 1, cell.state, cell.color)
                          self.grid.set_cell(x, yy, CellState.EMPTY, None)
                  lines_cleared += 1
              else:
                  y -= 1

          if lines_cleared > 0:
              self.score += self.calculate_score(lines_cleared)
              self.animation_timer = self.animation_frames

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 100
        elif lines_cleared == 2:
            return 300
        elif lines_cleared == 3:
            return 500
        elif lines_cleared == 4:
            return 800
        return 0

    def render(self):
        self.screen.fill((0, 0, 0))
        self.draw_grid()
        self.draw_tetromino()
        self.draw_next_tetromino()
        self.draw_score()
        if self.game_state == GameState.PAUSED:
            self.draw_pause_screen()
        if self.game_state == GameState.GAME_OVER:
            self.draw_game_over_screen()

    def draw_grid(self):
        for x in range(self.grid.width):
            for y in range(self.grid.height):
                cell = self.grid.get_cell(x, y)
                rect = pygame.Rect(x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                if cell.state == CellState.FILLED:
                    pygame.draw.rect(self.screen, cell.color, rect)
                    pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)
                else:
                    pygame.draw.rect(self.screen, EMPTY_COLOR, rect)
                    pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)

    def draw_tetromino(self):
        for block_x, block_y in self.current_tetromino.get_blocks(self.tetromino_x, self.tetromino_y):
            rect = pygame.Rect(block_x * BLOCK_SIZE, block_y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
            pygame.draw.rect(self.screen, self.current_tetromino.color, rect)
            pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)

    def draw_next_tetromino(self):
        font = pygame.font.Font(None, 30)
        text = font.render("Next Piece:", True, (255, 255, 255))
        self.screen.blit(text, (PREVIEW_POS[0], PREVIEW_POS[1] - 30))

        for block_x, block_y in self.next_tetromino.get_blocks():
            x = block_x + PREVIEW_POS[0] // BLOCK_SIZE
            y = block_y + (PREVIEW_POS[1] + 30) // BLOCK_SIZE
            rect = pygame.Rect(x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
            pygame.draw.rect(self.screen, self.next_tetromino.color, rect)
            pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)

    def draw_score(self):
        font = pygame.font.Font(None, 36)
        text = font.render(f"Score: {self.score}", True, (255, 255, 255))
        self.screen.blit(text, (420, 300))

    def draw_pause_screen(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 128))
        self.screen.blit(overlay, (0, 0))

        font = pygame.font.Font(None, 72)
        text = font.render("Paused", True, (255, 255, 255))
        text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(text, text_rect)

    def draw_game_over_screen(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 128))
        self.screen.blit(overlay, (0, 0))

        font = pygame.font.Font(None, 72)
        text = font.render("Game Over", True, (255, 255, 255))
        text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(text, text_rect)

        score_text = pygame.font.Font(None, 48).render(f"Final Score: {self.score}", True, (255, 255, 255))
        score_rect = score_text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2 + 60))
        self.screen.blit(score_text, score_rect)

if __name__ == '__main__':
    game = TetrisJeweled()
    game.run()
